// Extract project_id from various input formats
const input = $input.first().json;

let project_id = null;
let event_id = null;

// Format 1: Direct from Router
if (input.project_id) {
  project_id = input.project_id;
  event_id = input.event_id;
}
// Format 2: In body (Webhook direct call)
else if (input.body?.project_id) {
  project_id = input.body.project_id;
  event_id = input.body.event_id;
}
// Format 3: Wrapped in record (Supabase style)
else if (input.record?.project_id) {
  project_id = input.record.project_id;
  event_id = input.record.id;
}
// Format 4: In payload
else if (input.payload?.project_id) {
  project_id = input.payload.project_id;
  event_id = input.event_id;
}

if (!project_id) {
  throw new Error('No project_id found in input: ' + JSON.stringify(input).substring(0, 200));
}

return [{
  json: {
    project_id,
    event_id,
    started_at: new Date().toISOString()
  }
}];

// Final response
const extract = $('Extract Project ID').first().json;
const gen = $('Generate Materials').first().json;
const summary = $('Get Summary').all().map(i => i.json);
const event = $('Create MATERIALS_PLANNED Event').first().json;

return [{
  json: {
    status: 'success',
    project_id: extract.project_id,
    positions_processed: gen.positions_processed,
    materials_created: gen.materials_created,
    event_id: event.id,
    summary: summary,
    has_unassigned: summary.some(s => s.needs_assignment > 0)
  }
}];

// Check if any materials need product assignment
const summary = $('Get Summary').all();
const unassignedCount = summary.reduce((sum, item) => {
  return sum + (parseInt(item.json.needs_assignment) || 0);
}, 0);

if (unassignedCount > 0) {
  return [{
    json: {
      has_unassigned: true,
      unassigned_count: unassignedCount
    }
  }];
}

// Return empty to stop flow here
return [];

